import { Construct } from 'constructs';
import * as ec2 from 'aws-cdk-lib/aws-ec2';
import * as iam from 'aws-cdk-lib/aws-iam';
import * as elbv2 from 'aws-cdk-lib/aws-elasticloadbalancingv2';
import * as logs from 'aws-cdk-lib/aws-logs';

export class PmeStack extends Construct {
  constructor(scope: Construct, id: string, props?: cdk.StackProps) {
    super(scope, id, props);

    // VPC – use an existing VPC or create a new one
    const vpc = ec2.Vpc.fromLookup(this, 'VPC', { isDefault: true });

    // Security group – allow HTTPS only from trusted CIDR
    const sg = new ec2.SecurityGroup(this, 'PmeSG', {
      vpc,
      description: 'Allow HTTPS from corporate VPN only',
      allowAllOutbound: true,
    });
    sg.addIngressRule(
      ec2.Peer.ipv4('10.0.0.0/16'), // replace with your VPN CIDR
      ec2.Port.tcp(443),
      'HTTPS from corporate VPN'
    );

    // IAM role – least‑privilege
    const role = new iam.Role(this, 'PmeRole', {
      assumedBy: new iam.ServicePrincipal('ec2.amazonaws.com'),
      description: 'Role for PME instance – minimal permissions',
    });
    role.addManagedPolicy(
      iam.ManagedPolicy.fromAwsManagedPolicyName('AmazonSSMManagedInstanceCore')
    ); // only SSM for remote management

    // EC2 instance – run the patched PME image
    const instance = new ec2.Instance(this, 'PmeInstance', {
      vpc,
      instanceType: ec2.InstanceType.of(ec2.InstanceClass.T3, ec2.InstanceSize.MICRO),
      machineImage: ec2.MachineImage.genericLinux({
        'us-east-1': 'ami-0abcdef1234567890', // patched PME AMI
      }),
      securityGroup: sg,
      role,
      keyName: 'my-ssh-key', // optional
    });

    // ALB – front‑end for PME
    const alb = new elbv2.ApplicationLoadBalancer(this, 'PmeALB', {
      vpc,
      internetFacing: false,
      securityGroup: sg,
    });

    const listener = alb.addListener('HTTPSListener', {
      port: 443,
      certificates: [], // add ACM cert
      defaultTargetGroups: [
        new elbv2.ApplicationTargetGroup(this, 'PmeTG', {
          vpc,
          targets: [instance],
          protocol: elbv2.ApplicationProtocol.HTTP,
          healthCheck: { path: '/health' },
        }),
      ],
    });

    // CloudWatch logs for ALB
    const logGroup = new logs.LogGroup(this, 'AlbLogGroup', {
      retention: logs.RetentionDays.ONE_MONTH,
      removalPolicy: cdk.RemovalPolicy.DESTROY,
    });
    alb.logAccessLogs(logGroup);
  }
}
```

