## 3. AWS CDK Example – Updating a Tomcat Container in ECS

```ts
import * as cdk from 'aws-cdk-lib';
import { Construct } from 'constructs';
import * as ecs from 'aws-cdk-lib/aws-ecs';
import * as ec2 from 'aws-cdk-lib/aws-ec2';
import * as iam from 'aws-cdk-lib/aws-iam';

export class TomcatStack extends Construct {
  constructor(scope: Construct, id: string) {
    super(scope, id);

    // VPC
    const vpc = new ec2.Vpc(this, 'Vpc', { maxAzs: 2 });

    // ECS Cluster
    const cluster = new ecs.Cluster(this, 'Cluster', { vpc });

    // Task Definition – use the latest Tomcat image
    const taskDef = new ecs.FargateTaskDefinition(this, 'TaskDef', {
      cpu: 512,
      memoryLimitMiB: 1024,
    });

    // Secure IAM role for the task
    const taskRole = new iam.Role(this, 'TaskRole', {
      assumedBy: new iam.ServicePrincipal('ecs-tasks.amazonaws.com'),
    });
    taskRole.addManagedPolicy(
      iam.ManagedPolicy.fromAwsManagedPolicyName('service-role/AmazonECSTaskExecutionRolePolicy')
    );

    // Container
    taskDef.addContainer('Tomcat', {
      image: ecs.ContainerImage.fromRegistry('tomcat:10.1.21-jdk17'), // latest patched image
      portMappings: [{ containerPort: 8080 }],
      logging: ecs.LogDrivers.awsLogs({ streamPrefix: 'Tomcat' }),
    });

    // Service
    new ecs.FargateService(this, 'TomcatService', {
      cluster,
      taskDefinition: taskDef,
      desiredCount: 2,
      assignPublicIp: false,
      securityGroups: [new ec2.SecurityGroup(this, 'SG', { vpc })],
    });
  }
}
```

**Key Security Points**

1. **Image Pinning** – The image tag (`10.1.21-jdk17`) is immutable; avoid `latest`.
2. **Least‑Privilege IAM** – The task role only has the execution policy; no extra permissions.
3. **Logging** – CloudWatch Logs are enabled for auditability.
4. **Network Isolation** – No public IP; traffic enters via an Application Load Balancer (ALB) that can host WAF rules.

