import { Construct } from 'constructs';
import * as s3 from 'aws-cdk-lib/aws-s3';
import * as lambda from 'aws-cdk-lib/aws-lambda';
import * as iam from 'aws-cdk-lib/aws-iam';
import * as events from 'aws-cdk-lib/aws-events';
import * as targets from 'aws-cdk-lib/aws-events-targets';
import * as logs from 'aws-cdk-lib/aws-logs';
import * as sns from 'aws-cdk-lib/aws-sns';
import * as subscriptions from 'aws-cdk-lib/aws-sns-subscriptions';

export class SecureUploadStack extends cdk.Stack {
  constructor(scope: Construct, id: string, props?: cdk.StackProps) {
    super(scope, id, props);

    /* 1️⃣ Upload bucket – only authenticated writes, no public read */
    const uploadBucket = new s3.Bucket(this, 'UploadBucket', {
      bucketName: `${this.stackName}-uploads`,
      encryption: s3.BucketEncryption.S3_MANAGED,
      blockPublicAccess: s3.BlockPublicAccess.BLOCK_ALL,
      removalPolicy: cdk.RemovalPolicy.DESTROY, // for dev; use RETAIN in prod
      versioned: true,
      lifecycleRules: [
        { expiration: cdk.Duration.days(7) } // auto‑delete after 7 days
      ]
    });

    /* 2️⃣ Quarantine bucket – for suspicious files */
    const quarantineBucket = new s3.Bucket(this, 'QuarantineBucket', {
      bucketName: `${this.stackName}-quarantine`,
      encryption: s3.BucketEncryption.S3_MANAGED,
      blockPublicAccess: s3.BlockPublicAccess.BLOCK_ALL,
      removalPolicy: cdk.RemovalPolicy.DESTROY,
      versioned: true
    });

    /* 3️⃣ Lambda – validate & process uploads */
    const validator = new lambda.Function(this, 'UploadValidator', {
      runtime: lambda.Runtime.NODEJS_20_X,
      handler: 'validator.handler',
      code: lambda.Code.fromAsset('lambda'),
      timeout: cdk.Duration.seconds(30),
      environment: {
        QUARANTINE_BUCKET: quarantineBucket.bucketName,
        ALLOWED_MIME_TYPES: 'image/jpeg,image/png,application/pdf',
        MAX_FILE_SIZE: '10485760' // 10 MB
      },
      logRetention: logs.RetentionDays.ONE_WEEK
    });

    /* 4️⃣ IAM – least‑privilege for Lambda */
    uploadBucket.grantReadWrite(validator);
    quarantineBucket.grantWrite(validator);

    /* 5️⃣ EventBridge rule – trigger Lambda on S3 ObjectCreated */
    const rule = new events.Rule(this, 'S3ObjectCreatedRule', {
      eventPattern: {
        source: ['aws.s3'],
        detailType: ['Object Created'],
        detail: {
          bucket: { name: [uploadBucket.bucketName] }
        }
      }
    });
    rule.addTarget(new targets.LambdaFunction(validator));

    /* 6️⃣ SNS – alert on suspicious uploads */
    const alertTopic = new sns.Topic(this, 'UploadAlertTopic');
    alertTopic.addSubscription(new subscriptions.EmailSubscription('security@example.com'));

    /* 7️⃣ Grant Lambda permission to publish to SNS */
    alertTopic.grantPublish(validator);

    /* 8️⃣ CloudWatch Log Group – already created via logRetention */
  }
}
