### 2.2. CDK stack (TypeScript)

```ts
import * as cdk from 'aws-cdk-lib';
import { Construct } from 'constructs';
import * as cloudtrail from 'aws-cdk-lib/aws-cloudtrail';
import * as guardduty from 'aws-cdk-lib/aws-guardduty';
import * as securityhub from 'aws-cdk-lib/aws-securityhub';
import * as config from 'aws-cdk-lib/aws-config';
import * as iam from 'aws-cdk-lib/aws-iam';
import * as sns from 'aws-cdk-lib/aws-sns';
import * as lambda from 'aws-cdk-lib/aws-lambda';
import * as subscriptions from 'aws-cdk-lib/aws-sns-subscriptions';

export class SecurityHardeningStack extends Construct {
  constructor(scope: Construct, id: string) {
    super(scope, id);

    /* 1. CloudTrail – immutable logs */
    const trail = new cloudtrail.Trail(this, 'GlobalTrail', {
      isMultiRegionTrail: true,
      enableFileValidation: true,          // ensures integrity
      trailName: 'GlobalSecurityTrail',
      sendToCloudWatchLogs: true,
      cloudWatchLogGroupRetention: cdk.Duration.days(365),
    });

    /* 2. GuardDuty – threat detection */
    const detector = new guardduty.CfnDetector(this, 'GuardDutyDetector', {
      enable: true,
    });

    /* 3. Security Hub – central findings */
    const hub = new securityhub.CfnHub(this, 'SecurityHub', {
      enableDefaultStandards: true,
    });

    /* 4. Config – continuous compliance */
    new config.CfnConfigurationRecorder(this, 'ConfigRecorder', {
      name: 'SecurityRecorder',
      roleArn: new iam.Role(this, 'ConfigRole', {
        assumedBy: new iam.ServicePrincipal('config.amazonaws.com'),
        managedPolicies: [
          iam.ManagedPolicy.fromAwsManagedPolicyName('service-role/AWS_ConfigRole'),
        ],
      }).roleArn,
      recordingGroup: { allSupported: true, includeGlobalResourceTypes: true },
    });

    /* 5. SNS + Lambda – automated response to tampering */
    const topic = new sns.Topic(this, 'TamperAlertTopic');
    const lambdaFn = new lambda.Function(this, 'TamperResponder', {
      runtime: lambda.Runtime.NODEJS_18_X,
      handler: 'index.handler',
      code: lambda.Code.fromInline(`
        exports.handler = async (event) => {
          // Minimal, safe logic: log the event and optionally stop the offending service
          console.log('Tampering detected:', JSON.stringify(event, null, 2));
          // TODO: add logic to re‑enable services or alert SOC
          return { status: 'acknowledged' };
        };
      `),
      timeout: cdk.Duration.seconds(30),
    });

    topic.addSubscription(new subscriptions.LambdaSubscription(lambdaFn));

    /* 6. IAM SCP – prevent removal of monitoring services */
    const scp = new iam.ManagedPolicy(this, 'PreventMonitoringRemoval', {
      statements: [
        new iam.PolicyStatement({
          effect: iam.Effect.DENY,
          actions: [
            'cloudtrail:DeleteTrail',
            'guardduty:DeleteDetector',
            'securityhub:DeleteHub',
            'config:DeleteConfigurationRecorder',
          ],
          resources: ['*'],
        }),
      ],
    });

    // Attach SCP to the root OU (requires AWS Organizations)
    // (In CDK, SCPs are not directly supported; use AWS Organizations API or console)
  }
}
```

**Key security‑by‑design points**

- **Immutable logs**: `enableFileValidation` ensures CloudTrail logs cannot be tampered with.
- **Least‑privilege IAM**: The Config recorder role only has the `AWS_ConfigRole` policy.
- **Automated response**: Lambda receives tampering events via SNS; it can be extended to auto‑re‑enable services or trigger a SOC alert.
- **SCP**: Denies deletion of core monitoring services at the organization level.

