## 2. Cloud‑Native Implementation (AWS Example)

Below is a **CDK (TypeScript)** example that provisions a minimal, secure security‑tool stack:

```ts
import * as cdk from 'aws-cdk-lib';
import { Construct } from 'constructs';
import * as cloudtrail from 'aws-cdk-lib/aws-cloudtrail';
import * as guardduty from 'aws-cdk-lib/aws-guardduty';
import * as securityhub from 'aws-cdk-lib/aws-securityhub';
import * as s3 from 'aws-cdk-lib/aws-s3';
import * as iam from 'aws-cdk-lib/aws-iam';

export class SecurityToolsStack extends Construct {
  constructor(scope: Construct, id: string) {
    super(scope, id);

    /* 1️⃣ CloudTrail – capture all API activity */
    const trail = new cloudtrail.Trail(this, 'GlobalTrail', {
      isMultiRegionTrail: true,
      trailName: 'GlobalTrail',
      bucket: new s3.Bucket(this, 'TrailBucket', {
        encryption: s3.BucketEncryption.S3_MANAGED,
        versioned: true,
        removalPolicy: cdk.RemovalPolicy.RETAIN,
      }),
      includeGlobalServiceEvents: true,
      enableFileValidation: true,
    });

    /* 2️⃣ GuardDuty – threat detection */
    const detector = new guardduty.CfnDetector(this, 'GuardDutyDetector', {
      enable: true,
    });

    /* 3️⃣ Security Hub – central security posture */
    const hub = new securityhub.CfnHub(this, 'SecurityHub', {
      enableDefaultStandards: true,
    });

    /* 4️⃣ IAM role for Security Hub to ingest findings */
    const hubRole = new iam.Role(this, 'SecurityHubRole', {
      assumedBy: new iam.ServicePrincipal('securityhub.amazonaws.com'),
      managedPolicies: [
        iam.ManagedPolicy.fromAwsManagedPolicyName('SecurityHubFullAccess'),
      ],
    });

    /* 5️⃣ Grant CloudTrail logs to GuardDuty & Security Hub */
    trail.bucket.grantRead(detector);
    trail.bucket.grantRead(hubRole);
  }
}
```

