import { SnsTopic } from 'aws-cdk-lib/aws-sns';
import { LambdaFunction } from 'aws-cdk-lib/aws-lambda';

export class SecurityStack extends cdk.Stack {
  constructor(scope: cdk.App, id: string, props?: cdk.StackProps) {
    super(scope, id, props);

    // 1. GuardDuty
    const gd = new GuardDuty.GuardDutyDetector(this, 'GuardDuty', {
      enable: true,
      dataSources: {
        s3Logs: true,
        dnsLogs: true,
        flowLogs: true,
      },
    });

    // 2. Security Hub
    const sh = new SH.SecurityHub(this, 'SecurityHub', {
      enable: true,
    });

    // 3. SNS topic for alerts
    const topic = new SnsTopic(this, 'GuardDutyAlerts', {
      displayName: 'GuardDuty Alerts',
    });

    // 4. Lambda for automated remediation (e.g., block IP)
    const remediationFn = new LambdaFunction(this, 'RemediationFunction', {
      runtime: lambda.Runtime.NODEJS_18_X,
      handler: 'index.handler',
      code: lambda.Code.fromAsset('lambda'),
    });

    // 5. Grant permissions
    gd.grantFindingsTo(remediationFn);
    sh.grantFindingsTo(remediationFn);

    // 6. Subscribe Lambda to SNS
    topic.addSubscription(new subscriptions.LambdaSubscription(remediationFn));
  }
}
```

> **Security Note** – The snippet uses the CDK’s high‑level constructs, which internally apply least‑privilege IAM roles. No hard‑coded credentials or insecure patterns are present. The Lambda function should be written with input validation and error handling to avoid injection or privilege escalation.

