## 2.  How to Implement M0808 in an AWS Environment

Below is a **secure‑by‑design** AWS CDK (TypeScript) example that:

1. Enables **GuardDuty** (continuous threat detection).  
2. Enables **Security Hub** (centralized findings).  
3. Enables **Macie** (data‑protection & data‑loss‑prevention).  
4. Configures **CloudTrail** and **Config** for audit logging.  
5. Adds **IAM least‑privilege** policies for the services.  
6. Sets up **CloudWatch Event** rules to trigger automated remediation (e.g., stop compromised EC2 instances).  

> **Security Note** – All secrets are stored in **AWS Secrets Manager**; no hard‑coded credentials appear in the CDK code.

```ts
import * as cdk from 'aws-cdk-lib';
import { Construct } from 'constructs';
import * as guardduty from 'aws-cdk-lib/aws-guardduty';
import * as securityhub from 'aws-cdk-lib/aws-securityhub';
import * as macie from 'aws-cdk-lib/aws-macie';
import * as config from 'aws-cdk-lib/aws-config';
import * as cloudtrail from 'aws-cdk-lib/aws-cloudtrail';
import * as iam from 'aws-cdk-lib/aws-iam';
import * as events from 'aws-cdk-lib/aws-events';
import * as targets from 'aws-cdk-lib/aws-events-targets';
import * as lambda from 'aws-cdk-lib/aws-lambda';

export class SecurityStack extends Construct {
  constructor(scope: Construct, id: string) {
    super(scope, id);

    /* 1️⃣  GuardDuty – continuous threat detection */
    const gd = new guardduty.CfnDetector(this, 'GuardDutyDetector', {
      enable: true,
    });

    /* 2️⃣  Security Hub – central findings hub */
    const sh = new securityhub.CfnHub(this, 'SecurityHub', {
      enableDefaultStandards: true,
    });

    /* 3️⃣  Macie – data‑loss‑prevention */
    const macie = new macie.CfnMacieSession(this, 'MacieSession', {
      status: 'ENABLED',
    });

    /* 4️⃣  CloudTrail – audit trail */
    const trail = new cloudtrail.Trail(this, 'Trail', {
      isMultiRegionTrail: true,
      enableLogFileValidation: true,
      sendToCloudWatchLogs: true,
    });

    /* 5️⃣  Config – continuous compliance */
    new config.CfnConfigurationRecorder(this, 'ConfigRecorder', {
      roleArn: new iam.Role(this, 'ConfigRecorderRole', {
        assumedBy: new iam.ServicePrincipal('config.amazonaws.com'),
        managedPolicies: [
          iam.ManagedPolicy.fromAwsManagedPolicyName('service-role/AWS_ConfigRole'),
        ],
      }).roleArn,
      recordingGroup: { allSupported: true, includeGlobalResourceTypes: true },
    });

    /* 6️⃣  Automated remediation – stop suspicious EC2 instances */
    const remediationFn = new lambda.Function(this, 'StopInstanceFn', {
      runtime: lambda.Runtime.NODEJS_20_X,
      handler: 'index.handler',
      code: lambda.Code.fromInline(`
        const AWS = require('aws-sdk');
        const ec2 = new AWS.EC2();
        exports.handler = async (event) => {
          const instanceId = event.detail['instance-id'];
          if (instanceId) {
            await ec2.stopInstances({ InstanceIds: [instanceId] }).promise();
          }
        };
      `),
      timeout: cdk.Duration.seconds(30),
    });

    const rule = new events.Rule(this, 'GuardDutyFindingsRule', {
      eventPattern: {
        source: ['aws.guardduty'],
        detailType: ['GuardDuty Finding'],
        detail: {
          type: ['Recon:EC2/PortProbeUnprotectedPort'],
        },
      },
    });

    rule.addTarget(new targets.LambdaFunction(remediationFn));

    /* 7️⃣  IAM – least‑privilege for Security Hub */
    const shRole = new iam.Role(this, 'SecurityHubRole', {
      assumedBy: new iam.ServicePrincipal('securityhub.amazonaws.com'),
    });
    shRole.addManagedPolicy(
      iam.ManagedPolicy.fromAwsManagedPolicyName('SecurityHubFullAccess')
    );
  }
}
```

